diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..f331eddfe78d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2917,7 +2917,34 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
       return SelectInst::Create(NotCond, Constant::getAllOnesValue(SelType),
                                 TrueVal);
   }
-
+  // select (select C, X, false), TV, (select C, A, B) -> select C, (select X, TV, A), B
+  {
+    Value *C, *X, *A, *B;
+    if (match(CondVal, m_Select(m_Value(C), m_Value(X), m_Zero())) &&
+        match(FalseVal, m_Select(m_Specific(C), m_Value(A), m_Value(B)))) {
+      // Don't transform if both condition select and inner select have extra uses.
+      if (!CondVal->hasOneUse() && !FalseVal->hasOneUse())
+        /*skip*/;
+      else {
+        Value *InnerSel = Builder.CreateSelect(X, TrueVal, A);
+        return SelectInst::Create(C, InnerSel, B);
+      }
+    }
+  }
+  // select (select C, true, X), (select C, A, B), FV -> select C, A, (select X, B, FV)
+  {
+    Value *C, *X, *A, *B;
+    if (match(CondVal, m_Select(m_Value(C), m_One(), m_Value(X))) &&
+        match(TrueVal, m_Select(m_Specific(C), m_Value(A), m_Value(B)))) {
+      // Don't transform if both condition select and inner select have extra uses.
+      if (!CondVal->hasOneUse() && !TrueVal->hasOneUse())
+        /*skip*/;
+      else {
+        Value *InnerSel = Builder.CreateSelect(X, B, FalseVal);
+        return SelectInst::Create(C, A, InnerSel);
+      }
+    }
+  }
   if (Instruction *R = foldSelectOfBools(SI))
     return R;

